INSERT INTO public.recipes VALUES (4, 'ДРАНИКИ ИЗ КАБАЧКОВ', 'Кабачки лучшеиспользовать молодые, если у них уже появились семечки  в сердцевине, то обязательно удалите и семечки и кожуру
INSERT INTO public.recipes VALUES (5, 'ОВОЩНАЯ ЗАПЕКАНКА', 'Брокколи разобрать на соцветия и отварить в течении 1 минуты в слегка  подсоленной воде
INSERT INTO public.recipes VALUES (6, 'РАГУ С КРЕВЕТКАМИ', 'Креветки отварить до готовности в воде воде с солью, перцем и мелко  порезанным укропом
