INSERT INTO public.recipes VALUES (20, 'РЫБНЫЕ КОТЛЕТЫ', 'Из филе рыбы приготовьте фарш, добавьте яйцо, жир, соль, перец по  вкусу и перемешайте
INSERT INTO public.recipes VALUES (2, 'РЫБНЫЙ БУЛЬОН', 'Рыбные кости, брюшки, головы промыть, крупные части разрубить
INSERT INTO public.recipes VALUES (1, 'КОСТНЫЙ БУЛЬОН', 'Тщательно промойте кости под  проточной водой. Положите их во вместительную кастрюлю, добавьте лимонный сок,  очищенные овощи целиком, посолите и залейте водой. Доведите до кипения, снимите пену и убавьте огонь, чтобы бульон  слегка кипел с образованием мелких пузырьков. Варите под закрытой  крышкой 36 часов. Готовый бульон снимите с плиты, процедите через сито, овощи и  зелень можно выбросить. Бульон можно подавать как в горячем, так и в холодном виде,  принимать натощак или готовить на нем супы', 'GAPS.pdf');
